&lt;div&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/div&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Valid&lt;/strong&gt;:&amp;nbsp;Logically sound; having a basis in fact. (वैध)&lt;/span&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Example&lt;/strong&gt;: The scientist&amp;#39;s hypothesis was &lt;strong&gt;valid&lt;/strong&gt;, supported by years of research.&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Genuine&lt;/strong&gt;: Real; not fake or counterfeit. (असली)&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Example&lt;/strong&gt;: The painting was a &lt;strong&gt;genuine &lt;/strong&gt;Rembrandt, not a copy.&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Effusive&lt;/strong&gt;: Expressive or emotional in a gushing or unrestrained way. (अत्यधिक भावुक या असंयत)&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Example&lt;/strong&gt;: She was &lt;strong&gt;effusive &lt;/strong&gt;in her praise for her friend&amp;#39;s accomplishments.&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;strong&gt;Gradual.&amp;nbsp;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;Abrupt:&amp;nbsp;&lt;/strong&gt;&lt;span style=&quot;color: rgb(34, 34, 34);  &quot;&gt;sudden and unexpected&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(34, 34, 34);  &quot;&gt;&lt;strong&gt;Gradual&lt;/strong&gt;:&amp;nbsp;taking place or progressing slowly or by degrees; not sudden&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(34, 34, 34);  &quot;&gt;Thus we can see that Abrupt and Gradual are antonyms.&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(34, 34, 34);  &quot;&gt;The meaning of the other words:&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(34, 34, 34);  &quot;&gt;&lt;strong&gt;Unanticipated&lt;/strong&gt;:&amp;nbsp;not expected or predicted&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(34, 34, 34);  &quot;&gt;&lt;strong&gt;Startling&lt;/strong&gt;:&amp;nbsp;very surprising, astonishing, or remarkable&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Unexpected&lt;/strong&gt;:&amp;nbsp;&lt;span style=&quot;color: rgb(34, 34, 34);  &quot;&gt;not expected or regarded as likely to happen&lt;/span&gt;&lt;br /&gt;
	&lt;span id=&quot;docs-internal-guid-d5ed4ec7-7fff-1417-e71b-23705a7aeacb&quot;&gt;&lt;span style=&quot;  background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;&quot;&gt;&lt;span style=&quot;border:none;display:inline-block;overflow:hidden;width:212px;height:51px;&quot;&gt;&lt;img height=&quot;51&quot; src=&quot;https://lh5.googleusercontent.com/7aerTqT7mtawKIc4K5b7Oup-lL8z5FuHcAbSPXFTY8HGz8LNhc_3ZiBn91GGjpsLl6Q5OLMbkc9PdCtl-WV8fV_eaSJs8T2NSLuVoCu0sEWgFRU77DjNbBVBdHs7StZ4l1CNFYln&quot; style=&quot;margin-left:0px;margin-top:0px;&quot; width=&quot;212&quot; /&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:500px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td&gt;A&lt;strong&gt;brup&lt;/strong&gt;t&lt;/td&gt;
			&lt;td&gt;meeting with &lt;strong&gt;rub&lt;/strong&gt; [God] cannot be &lt;strong&gt;abrupt&lt;/strong&gt;.&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;&lt;strong&gt;Gradual&lt;/strong&gt;&lt;/td&gt;
			&lt;td&gt;&lt;strong&gt;graduation&lt;/strong&gt; is a &lt;strong&gt;gradual &lt;/strong&gt;process.&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;&lt;strong&gt;Start&lt;/strong&gt;ling&lt;/td&gt;
			&lt;td&gt;John &lt;strong&gt;started &lt;/strong&gt;startling looking at evening &lt;strong&gt;star &lt;/strong&gt;for the first time.&lt;/td&gt;
